package main.rice.parse;

import main.rice.node.APyNode;
import java.util.List;

/**
 * A data class representing a parsed configuration file.
 * Contains the function name, list of PyNodes for arguments, and the number of random tests.
 */
public class ConfigFile {

    private String funcName;
    private List<APyNode<?>> nodes;
    private int numRand;

    /**
     * Constructor for ConfigFile.
     *
     * @param funcName the name of the function being tested
     * @param nodes the list of PyNodes representing the arguments
     * @param numRand the number of random test cases to generate
     */
    public ConfigFile(String funcName, List<APyNode<?>> nodes, int numRand) {
        this.funcName = funcName;
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Returns the function name being tested.
     *
     * @return the function name
     */
    public String getFuncName() {
        return this.funcName;
    }

    /**
     * Returns the number of random test cases to generate.
     *
     * @return the number of random tests
     */
    public int getNumRand() {
        return this.numRand;
    }

    /**
     * Returns the list of PyNodes representing the arguments.
     *
     * @return the list of PyNodes
     */
    public List<APyNode<?>> getNodes() {
        return this.nodes;
    }
}

