package main.rice.parse;

import main.rice.node.*;
import main.rice.obj.APyObj;
import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

import java.util.*;
import java.util.regex.Pattern;

/**
 * A parser for JSON configuration files that creates ConfigFile objects with appropriate PyNodes.
 */
public class ConfigFileParser {

    /**
     * Parses a JSON string into a ConfigFile object.
     *
     * @param jsonStr the JSON string to parse
     * @return a ConfigFile object containing the parsed configuration
     * @throws InvalidConfigException if the JSON is malformed or validation fails
     */
    public ConfigFile parse(String jsonStr) throws InvalidConfigException {
        try {
            JSONObject json = new JSONObject(jsonStr);

            // Validate required fields exist
            validateRequiredFields(json);

            // Validate field types
            validateFieldTypes(json);

            // Parse basic fields
            String fname = json.getString("fname");
            JSONArray typesArray = json.getJSONArray("types");
            JSONArray exDomainArray = json.getJSONArray("exhaustive domain");
            JSONArray ranDomainArray = json.getJSONArray("random domain");
            int numRand = json.getInt("num random");

            // Validate numRand
            if (numRand < 0) {
                throw new InvalidConfigException("num random must be non-negative, got: " + numRand);
            }

            // Convert arrays to lists of strings
            List<String> types = new ArrayList<>();
            for (int i = 0; i < typesArray.length(); i++) {
                types.add(typesArray.getString(i));
            }

            List<String> exDomains = new ArrayList<>();
            for (int i = 0; i < exDomainArray.length(); i++) {
                exDomains.add(exDomainArray.getString(i));
            }

            List<String> ranDomains = new ArrayList<>();
            for (int i = 0; i < ranDomainArray.length(); i++) {
                ranDomains.add(ranDomainArray.getString(i));
            }

            // Validate array lengths match
            if (types.size() != exDomains.size() || types.size() != ranDomains.size()) {
                throw new InvalidConfigException(
                    "types, exhaustive domain, and random domain arrays must have the same length");
            }

            // Create nodes
            List<APyNode<?>> nodes = new ArrayList<>();
            for (int i = 0; i < types.size(); i++) {
                APyNode<?> node = createNode(types.get(i), exDomains.get(i), ranDomains.get(i));
                nodes.add(node);
            }

            return new ConfigFile(fname, nodes, numRand);

        } catch (JSONException e) {
            throw new InvalidConfigException("Invalid JSON: " + e.getMessage());
        }
    }

    /**
     * Validates that all required fields are present in the JSON object.
     */
    private void validateRequiredFields(JSONObject json) throws InvalidConfigException {
        String[] requiredFields = {"fname", "types", "exhaustive domain", "random domain", "num random"};
        for (String field : requiredFields) {
            if (!json.has(field)) {
                throw new InvalidConfigException("Missing required field: " + field);
            }
        }
    }

    /**
     * Validates that all fields have the correct types.
     */
    private void validateFieldTypes(JSONObject json) throws InvalidConfigException {
        // fname must be String
        if (!(json.get("fname") instanceof String)) {
            throw new InvalidConfigException("fname must be a string");
        }

        // types must be JSONArray of Strings
        if (!(json.get("types") instanceof JSONArray)) {
            throw new InvalidConfigException("types must be an array");
        }
        JSONArray typesArray = json.getJSONArray("types");
        for (int i = 0; i < typesArray.length(); i++) {
            if (!(typesArray.get(i) instanceof String)) {
                throw new InvalidConfigException("types must be an array of strings");
            }
        }

        // exhaustive domain must be JSONArray of Strings
        if (!(json.get("exhaustive domain") instanceof JSONArray)) {
            throw new InvalidConfigException("exhaustive domain must be an array");
        }
        JSONArray exDomainArray = json.getJSONArray("exhaustive domain");
        for (int i = 0; i < exDomainArray.length(); i++) {
            if (!(exDomainArray.get(i) instanceof String)) {
                throw new InvalidConfigException("exhaustive domain must be an array of strings");
            }
        }

        // random domain must be JSONArray of Strings
        if (!(json.get("random domain") instanceof JSONArray)) {
            throw new InvalidConfigException("random domain must be an array");
        }
        JSONArray ranDomainArray = json.getJSONArray("random domain");
        for (int i = 0; i < ranDomainArray.length(); i++) {
            if (!(ranDomainArray.get(i) instanceof String)) {
                throw new InvalidConfigException("random domain must be an array of strings");
            }
        }

        // num random must be an integer
        Object numRandObj = json.get("num random");
        if (!(numRandObj instanceof Integer || numRandObj instanceof Long)) {
            throw new InvalidConfigException("num random must be an integer");
        }
    }

    /**
     * Creates an appropriate APyNode from a type string and domain specification.
     */
    private APyNode<?> createNode(String typeStr, String exDomainStr, String ranDomainStr)
            throws InvalidConfigException {
        // Validate no spurious characters in type string
        validateTypeString(typeStr);

        // Parse domain strings
        List<Integer> exDomain = parseDomain(exDomainStr);
        List<Integer> ranDomain = parseDomain(ranDomainStr);

        // Create the node based on type
        APyNode<?> node = createNodeForType(typeStr);
        node.setExDomain(exDomain);
        node.setRanDomain(ranDomain);

        return node;
    }

    /**
     * Validates that a type string contains no spurious parentheses or spaces.
     */
    private void validateTypeString(String typeStr) throws InvalidConfigException {
        // Check for spaces
        if (typeStr.contains(" ")) {
            throw new InvalidConfigException("Type string contains spurious space: " + typeStr);
        }

        // Check for spurious parentheses
        // Valid patterns: "int", "bool", "float", "str", "list(T)", "set(T)", "tuple(T)", "dict(K:V)"
        // Invalid: "int(", "int)", etc.
        if (!isValidTypeFormat(typeStr)) {
            throw new InvalidConfigException("Type string contains spurious parentheses: " + typeStr);
        }
    }

    /**
     * Checks if a type string is valid.
     */
    private boolean isValidTypeFormat(String typeStr) {
        // Base types
        if (typeStr.equals("int") || typeStr.equals("bool") || typeStr.equals("float") || typeStr.equals("str")) {
            return true;
        }

        // Collection types: list(T), set(T), tuple(T), dict(K:V)
        if (typeStr.startsWith("list(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(5, typeStr.length() - 1);
            return isValidTypeFormat(inner);
        }
        if (typeStr.startsWith("set(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(4, typeStr.length() - 1);
            return isValidTypeFormat(inner);
        }
        if (typeStr.startsWith("tuple(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(6, typeStr.length() - 1);
            return isValidTypeFormat(inner);
        }
        if (typeStr.startsWith("dict(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(5, typeStr.length() - 1);
            // dict should have K:V format
            String[] parts = inner.split(":");
            return parts.length == 2 && isValidTypeFormat(parts[0]) && isValidTypeFormat(parts[1]);
        }

        return false;
    }

    /**
     * Creates a node for the given type string. Recursively handles nested types.
     */
    private APyNode<?> createNodeForType(String typeStr) throws InvalidConfigException {
        if (typeStr.equals("int")) {
            return new PyIntNode();
        } else if (typeStr.equals("bool")) {
            return new PyBoolNode();
        } else if (typeStr.equals("float")) {
            return new PyFloatNode();
        } else if (typeStr.equals("str")) {
            return new PyStringNode("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789");
        } else if (typeStr.startsWith("list(") && typeStr.endsWith(")")) {
            String innerType = typeStr.substring(5, typeStr.length() - 1);
            APyNode<?> innerNode = createNodeForType(innerType);
            return createListNode(innerNode);
        } else if (typeStr.startsWith("set(") && typeStr.endsWith(")")) {
            String innerType = typeStr.substring(4, typeStr.length() - 1);
            APyNode<?> innerNode = createNodeForType(innerType);
            return createSetNode(innerNode);
        } else if (typeStr.startsWith("tuple(") && typeStr.endsWith(")")) {
            String innerType = typeStr.substring(6, typeStr.length() - 1);
            APyNode<?> innerNode = createNodeForType(innerType);
            return createTupleNode(innerNode);
        } else if (typeStr.startsWith("dict(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(5, typeStr.length() - 1);
            String[] parts = inner.split(":");
            APyNode<?> keyNode = createNodeForType(parts[0]);
            APyNode<?> valNode = createNodeForType(parts[1]);
            return createDictNode(keyNode, valNode);
        } else {
            throw new InvalidConfigException("Invalid type: " + typeStr);
        }
    }

    /**
     * Helper method to create a PyListNode with proper type erasure.
     */
    @SuppressWarnings("unchecked")
    private PyListNode<?> createListNode(APyNode<?> innerNode) {
        return new PyListNode(innerNode);
    }

    /**
     * Helper method to create a PySetNode with proper type erasure.
     */
    @SuppressWarnings("unchecked")
    private PySetNode<?> createSetNode(APyNode<?> innerNode) {
        return new PySetNode(innerNode);
    }

    /**
     * Helper method to create a PyTupleNode with proper type erasure.
     */
    @SuppressWarnings("unchecked")
    private PyTupleNode<?> createTupleNode(APyNode<?> innerNode) {
        return new PyTupleNode(innerNode);
    }

    /**
     * Helper method to create a PyDictNode with proper type erasure.
     */
    @SuppressWarnings("unchecked")
    private PyDictNode<?, ?> createDictNode(APyNode<?> keyNode, APyNode<?> valNode) {
        return new PyDictNode(keyNode, valNode);
    }

    /**
     * Parses a domain string into a list of integers.
     * Supports formats like:
     * - "1~10" (range)
     * - "[1]" (explicit list)
     * - "0~2;0~1" (multiple ranges, for nested types)
     */
    private List<Integer> parseDomain(String domainStr) throws InvalidConfigException {
        // Validate no spurious characters
        validateDomainString(domainStr);

        List<Integer> result = new ArrayList<>();

        // Check for explicit list format [1, 2, 3]
        if (domainStr.startsWith("[") && domainStr.endsWith("]")) {
            String content = domainStr.substring(1, domainStr.length() - 1);
            if (content.isEmpty()) {
                return result; // empty list
            }
            String[] parts = content.split(",");
            for (String part : parts) {
                part = part.trim();
                try {
                    result.add(Integer.parseInt(part));
                } catch (NumberFormatException e) {
                    throw new InvalidConfigException("Invalid domain value: " + part);
                }
            }
            return result;
        }

        // Check for multiple ranges separated by semicolon (for nested types)
        if (domainStr.contains(";")) {
            String[] rangeParts = domainStr.split(";");
            for (String rangePart : rangeParts) {
                List<Integer> rangeValues = parseRange(rangePart);
                // For multiple ranges, we typically only care about the first (outer) range
                if (result.isEmpty()) {
                    result.addAll(rangeValues);
                }
                // Or we could accumulate them - depends on interpretation
                // For now, just taking first range
            }
            return result;
        }

        // Single range: "1~10"
        return parseRange(domainStr);
    }

    /**
     * Parses a single range string like "1~10" into a list [1, 2, ..., 10].
     */
    private List<Integer> parseRange(String rangeStr) throws InvalidConfigException {
        List<Integer> result = new ArrayList<>();

        if (!rangeStr.contains("~")) {
            throw new InvalidConfigException("Domain range must contain '~': " + rangeStr);
        }

        String[] parts = rangeStr.split("~");
        if (parts.length != 2) {
            throw new InvalidConfigException("Invalid range format: " + rangeStr);
        }

        try {
            int lower = Integer.parseInt(parts[0]);
            int upper = Integer.parseInt(parts[1]);

            if (lower > upper) {
                throw new InvalidConfigException("Invalid range: lower > upper in " + rangeStr);
            }

            for (int i = lower; i <= upper; i++) {
                result.add(i);
            }
        } catch (NumberFormatException e) {
            throw new InvalidConfigException("Invalid range bounds: " + rangeStr);
        }

        return result;
    }

    /**
     * Validates that a domain string contains no spurious characters.
     */
    private void validateDomainString(String domainStr) throws InvalidConfigException {
        // Check for spaces around ~
        if (domainStr.contains(" ~ ") || domainStr.contains("~ ") || domainStr.contains(" ~")) {
            throw new InvalidConfigException("Domain string contains spurious space: " + domainStr);
        }

        // Check for spurious parentheses (should only be in type names within dict domains)
        // More lenient check - just ensure the format is reasonable
        if (domainStr.matches(".*[()]{2,}.*")) {
            // Multiple consecutive parentheses is suspicious
            throw new InvalidConfigException("Domain string contains spurious parentheses: " + domainStr);
        }
    }
}

