package main.rice;

import main.rice.basegen.BaseSetGenerator;
import main.rice.concisegen.ConciseSetGenerator;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import main.rice.test.TestCase;
import main.rice.test.Tester;
import main.rice.test.TestResults;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;
import java.util.Set;

/**
 * Main entry point for the config file parser and test generation system.
 * Combines all components to generate a minimal test set.
 */
public class Main {

    /**
     * Generates a minimal set of test cases that can catch bugs in various implementations.
     *
     * The process:
     * 1. Parse the configuration file
     * 2. Generate base test cases using BaseSetGenerator
     * 3. Run tests against all implementations using Tester
     * 4. Find minimal test set using ConciseSetGenerator
     *
     * @param args command-line arguments: [config_path, solution_path, impl_dir_path]
     * @return a set of test cases that form a minimal test set
     * @throws InvalidConfigException if the configuration is invalid
     * @throws IOException if there are file I/O errors
     * @throws InterruptedException if the test process is interrupted
     */
    public static Set<TestCase> generateTests(String[] args)
            throws InvalidConfigException, IOException, InterruptedException {

        // Parse command-line arguments
        if (args.length < 3) {
            throw new IllegalArgumentException("Usage: Main <config_path> <solution_path> <impl_dir_path>");
        }

        String configPath = args[0];
        String solutionPath = args[1];
        String implDirPath = args[2];

        // Read and parse the configuration file
        String configJson = Files.readString(Paths.get(configPath));
        ConfigFileParser parser = new ConfigFileParser();
        ConfigFile config = parser.parse(configJson);

        // Generate the base test set
        BaseSetGenerator baseGen = new BaseSetGenerator(config.getNodes(), config.getNumRand());
        List<TestCase> baseTests = baseGen.genBaseSet();

        // Run tests on all implementations
        Tester tester = new Tester(config.getFuncName(), solutionPath, implDirPath, baseTests);
        TestResults results = tester.runTests();

        // Find the minimal test set that catches all bugs
        Set<TestCase> conciseSet = ConciseSetGenerator.setCover(results);

        return conciseSet;
    }

    /**
     * Main method to run the test generation system.
     *
     * @param args command-line arguments: [config_path, solution_path, impl_dir_path]
     */
    public static void main(String[] args) {
        try {
            Set<TestCase> result = generateTests(args);
            System.out.println("Generated " + result.size() + " test cases");
            for (TestCase testCase : result) {
                System.out.println(testCase);
            }
        } catch (InvalidConfigException e) {
            System.err.println("Configuration error: " + e.getMessage());
            System.exit(1);
        } catch (IOException e) {
            System.err.println("I/O error: " + e.getMessage());
            System.exit(1);
        } catch (InterruptedException e) {
            System.err.println("Process interrupted: " + e.getMessage());
            System.exit(1);
        }
    }
}

