/**
 * Creates an appropriate APyNode from a type string and domain specification.
 */
private APyNode<?> createNode(String typeStr, String exDomainStr, String ranDomainStr)
        throws InvalidConfigException {
    // Validate no spurious characters in type string
    validateTypeString(typeStr);

    // Validate domain strings
    validateDomainString(exDomainStr);
    validateDomainString(ranDomainStr);

    // Create the node with domain specifications
    return createNodeWithDomains(typeStr, exDomainStr, ranDomainStr);
}

/**
 * Creates a node with domain specifications, handling nested types recursively.
 */
private APyNode<?> createNodeWithDomains(String typeStr, String exDomainStr, String ranDomainStr)
        throws InvalidConfigException {
    // Base case: simple types
    if (typeStr.equals("int") || typeStr.equals("bool") ||
        typeStr.equals("float") || typeStr.equals("str")) {
        APyNode<?> node = createNodeForType(typeStr);
        List<Integer> exDomain = parseDomain(exDomainStr);
        List<Integer> ranDomain = parseDomain(ranDomainStr);
        node.setExDomain(exDomain);
        node.setRanDomain(ranDomain);
        return node;
    }

    // Nested types: parse domain strings to extract outer and inner domains
    // For "list(int)" with domain "0~2;1~3": outer domain is "0~2", inner is "1~3"
    String[] exDomainParts = exDomainStr.split(";", -1);
    String[] ranDomainParts = ranDomainStr.split(";", -1);

    String outerExDomain = exDomainParts[0];
    String outerRanDomain = ranDomainParts[0];
    String innerExDomain = exDomainParts.length > 1 ? exDomainParts[1] : exDomainParts[0];
    String innerRanDomain = ranDomainParts.length > 1 ? ranDomainParts[1] : ranDomainParts[0];

    // Create nested nodes
    if (typeStr.startsWith("list(") && typeStr.endsWith(")")) {
        String innerType = typeStr.substring(5, typeStr.length() - 1);
        APyNode<?> innerNode = createNodeWithDomains(innerType, innerExDomain, innerRanDomain);
        APyNode<?> listNode = createListNode(innerNode);
        List<Integer> outerExDom = parseDomain(outerExDomain);
        List<Integer> outerRanDom = parseDomain(outerRanDomain);
        listNode.setExDomain(outerExDom);
        listNode.setRanDomain(outerRanDom);
        return listNode;
    } else if (typeStr.startsWith("set(") && typeStr.endsWith(")")) {
        String innerType = typeStr.substring(4, typeStr.length() - 1);
        APyNode<?> innerNode = createNodeWithDomains(innerType, innerExDomain, innerRanDomain);
        APyNode<?> setNode = createSetNode(innerNode);
        List<Integer> outerExDom = parseDomain(outerExDomain);
        List<Integer> outerRanDom = parseDomain(outerRanDomain);
        setNode.setExDomain(outerExDom);
        setNode.setRanDomain(outerRanDom);
        return setNode;
    } else if (typeStr.startsWith("tuple(") && typeStr.endsWith(")")) {
        String innerType = typeStr.substring(6, typeStr.length() - 1);
        APyNode<?> innerNode = createNodeWithDomains(innerType, innerExDomain, innerRanDomain);
        APyNode<?> tupleNode = createTupleNode(innerNode);
        List<Integer> outerExDom = parseDomain(outerExDomain);
        List<Integer> outerRanDom = parseDomain(outerRanDomain);
        tupleNode.setExDomain(outerExDom);
        tupleNode.setRanDomain(outerRanDom);
        return tupleNode;
    } else if (typeStr.startsWith("dict(") && typeStr.endsWith(")")) {
        String inner = typeStr.substring(5, typeStr.length() - 1);
        String[] typeParts = inner.split(":");
        String keyType = typeParts[0];
        String valType = typeParts[1];
        APyNode<?> keyNode = createNodeWithDomains(keyType, innerExDomain, innerRanDomain);
        APyNode<?> valNode = createNodeWithDomains(valType, innerExDomain, innerRanDomain);
        APyNode<?> dictNode = createDictNode(keyNode, valNode);
        List<Integer> outerExDom = parseDomain(outerExDomain);
        List<Integer> outerRanDom = parseDomain(outerRanDomain);
        dictNode.setExDomain(outerExDom);
        dictNode.setRanDomain(outerRanDom);
        return dictNode;
    } else {
        throw new InvalidConfigException("Invalid type: " + typeStr);
    }
}

